// 1. 抓取 OpenAI 吐出來的那串 "長得像 JSON 的文字"
// 注意：這裡的路徑是根據你剛剛貼給我的 output 結構抓的
const aiText = $input.first().json.output[0].content[0].text;

// 2. 用 JSON.parse 把文字 "拆開" 變成真正的物件
const parsedData = JSON.parse(aiText);

// 3. 回傳乾淨的資料
return parsedData;

