// 1. 抓取 LINE 傳回來的 data 字串
const event = $input.first().json.body.events[0];
const dataString = event.postback.data;
const replyToken = event.replyToken;

// 2. 手動解析資料 (因為 n8n 不支援 URLSearchParams，我們自己切字串)
// 原本格式: "action=confirm_send&id=123&email=abc"
const params = {};
dataString.split('&').forEach(part => {
  const [key, value] = part.split('=');
  if (key && value) {
    // decodeURIComponent 是為了把網址編碼轉回中文或特殊符號
    params[key] = decodeURIComponent(value);
  }
});

// 3. 整理成乾淨的欄位吐出去
return {
  action: params['action'],
  fileId: params['id'],
  email: params['email'],
  name: params['name'],
  replyToken: replyToken
};

// 🏠 民宿設定
const propertyMap = {
  "淺草千之森": { id: "10yZhQRv9Om7m0zKgP-W0UB9n-6wAx1fGD9S8bq1RVew", prefix: "AS" },
  "銀婚屋": { id: "1h0il0jq6V3I3Qo9fHUp2nDqjDDIZ_myd2tbc6WAQXUQ", prefix: "IG" },
  "鑫之屋": { id: "1mIDTlGTukMhyxpOH_fOy2omqpN16hwDtzFGBYAJwlvE", prefix: "IS" },
  "高田馬場": { id: "1LJoaFc51BKi8-Dqj1VdnVhZZ0rbdsLVgNoNzt8VZOTI", prefix: "TAKA" },
  "笹塚stay": { id: "1qYZJX6fquipUxyfJ4j3HKp32h1rGqaK7pFP3yk1gC2w", prefix: "SAX" },
  "新宿中落合": { id: "1lsXSXOd88y81bkYLbbpF9FIMQ00lMzfquG8HhZKljiY", prefix: "NAKA" },
  // 👇 這是新增的部分
  "押上～晴空緣": { id: "1x5It1TFJzX9N54UP9Dq7XcxVilgwcalIlVqewmdG7iM", prefix: "ST" }
};

const formData = $('On form submission').item.json;
const selected = formData["選擇民宿"];
const propertyData = propertyMap[selected];

if (!propertyData) {
  throw new Error(`⚠️ 找不到民宿: "${selected}"`);
}

// 🛠️ 判斷號碼邏輯
let bookingNo = formData["預約號碼"]; 

if (!bookingNo || bookingNo.trim() === "") {
  const today = new Date();
  const dateStr = today.getFullYear().toString() + 
                  (today.getMonth() + 1).toString().padStart(2, '0') + 
                  today.getDate().toString().padStart(2, '0');
  bookingNo = propertyData.prefix + dateStr;
}

return { 
  file_id: propertyData.id,
  generatedBookingNo: bookingNo 
};
